const launch = $('Get Launch-Day Launches').item.json;
const briefs = $('Load All Briefs').all().map(i => i.json);
const readinessHistory = $('Load Readiness History').all().map(i => i.json);

// Build the launch packet
const intelBriefs = briefs.filter(b => b.brief_type === 'intelligence');
const totalSignals = briefs.reduce((sum, b) => sum + (b.signal_count || 0), 0);

// Readiness trend
const scores = readinessHistory.map(r => r.score);
const trend = scores.length >= 2
  ? scores[0] > scores[scores.length - 1] ? 'improving' : scores[0] < scores[scores.length - 1] ? 'declining' : 'stable'
  : 'insufficient data';

// Compile latest risks and opportunities
const latestRisks = readinessHistory.length > 0 ? (readinessHistory[0].risk_factors || []) : [];
const latestOpportunities = readinessHistory.length > 0 ? (readinessHistory[0].opportunities || []) : [];

const packetTitle = `Launch Packet — ${launch.launch_name}`;
const packetMd = `# ${packetTitle}\n**Product:** ${launch.product_name}\n**Launch Date:** ${launch.target_launch_date}\n**Readiness Score:** ${launch.readiness_score}/100 (${trend})\n\n---\n\n## Pre-Launch Intelligence Summary\n- ${intelBriefs.length} intelligence briefs generated\n- ${totalSignals} total signals consumed\n- Readiness trend: ${trend}\n\n## Readiness Score History\n${readinessHistory.map(r => `- ${r.check_date}: ${r.score}/100`).join('\n')}\n\n## Active Risks\n${(typeof latestRisks === 'string' ? JSON.parse(latestRisks) : latestRisks).map(r => `- **${r.label}**: ${r.detail}`).join('\n') || 'None'}\n\n## Opportunities\n${(typeof latestOpportunities === 'string' ? JSON.parse(latestOpportunities) : latestOpportunities).map(o => `- **${o.label}**: ${o.detail}`).join('\n') || 'None'}\n\n## Competitors\n${(launch.competitor_names || []).map(c => `- ${c}`).join('\n') || 'None tracked'}\n\n---\n*Generated automatically by Signal Plane Launch Operations*`;

return [{
  json: {
    launch_id: launch.launch_id,
    user_id: launch.user_id,
    packet_title: packetTitle,
    packet_md: packetMd,
    packet_json: JSON.stringify({
      readiness_score: launch.readiness_score,
      readiness_trend: trend,
      intelligence_briefs_count: intelBriefs.length,
      total_signals: totalSignals,
      risks: latestRisks,
      opportunities: latestOpportunities
    }),
    total_signals: totalSignals
  }
}];
